        {
            if (b == 0)
                return Request.CreateErrorResponse(HttpStatusCode.BadRequest, "Cannot divide by zero.");

            double result = (double)a / b;
            return Request.CreateResponse(HttpStatusCode.OK, result);
        }
    }
}
```

